SELECT upgrade.upgrade, count(*) AS change FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline ON baseline.bldg_id = upgrade.bldg_id WHERE baseline.applicability = true AND upgrade.applicability = true AND true GROUP BY 1 ORDER BY 1